const express = require('express');
const projectsRouter = require('./modules/projects/routes');
const membersRouter = require('./modules/members/routes');
const tasksRouter = require('./modules/tasks/routes');
const commentsRouter = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRouter);
app.use('/projects/:projectId/members', membersRouter);
app.use('/projects/:projectId/tasks', tasksRouter);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRouter);

module.exports = app;

const express = require('express');
const app = require('./app');
const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

const express = require('express');
const { sendError } = require('../../lib/errors');
const projectService = require('./service');

const router = express.Router();

router.get('/', (req, res) => {
  const projects = projectService.getAllProjects();
  res.json({ projects });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) return sendError(res, 400, 'INVALID_NAME', 'Name is required');

  const project = projectService.createProject(name);
  res.status(201).json({ project });
});

module.exports = router;

const { randomUUID } = require('node:crypto');

let projects = [];

function getAllProjects() {
  return projects;
}

function createProject(name) {
  const project = { id: randomUUID(), name };
  projects.push(project);
  return project;
}

module.exports = {
  getAllProjects,
  createProject,
};

const express = require('express');
const { sendError } = require('../../lib/errors');
const memberService = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) return sendError(res, 400, 'INVALID_INPUT', 'UserId and role are required');

  const member = memberService.addMember(req.params.projectId, userId, role);
  res.status(201).json({ member });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const projectService = require('../projects/service');

let members = [];

function addMember(projectId, userId, role) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) return null;

  const member = { id: randomUUID(), projectId, userId, role };
  members.push(member);
  return member;
}

module.exports = {
  addMember,
};

const express = require('express');
const { sendError } = require('../../lib/errors');
const taskService = require('./service');

const router = express.Router();

router.get('/', (req, res) => {
  const tasks = taskService.getAllTasks(req.params.projectId);
  if (req.query.status === 'done') {
    const doneTasks = tasks.filter(task => task.status === 'done');
    return res.json({ tasks: doneTasks });
  }
  res.json({ tasks });
});

router.post('/', (req, res) => {
  const { title } = req.body;
  if (!title) return sendError(res, 400, 'INVALID_TITLE', 'Title is required');

  const task = taskService.createTask(req.params.projectId, title);
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) return sendError(res, 400, 'INVALID_STATUS', 'Status must be todo or done');

  const task = taskService.updateTask(req.params.projectId, req.params.taskId, status);
  if (!task) return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');

  res.json({ task });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const projectService = require('../projects/service');

let tasks = [];

function getAllTasks(projectId) {
  return tasks.filter(task => task.projectId === projectId);
}

function createTask(projectId, title) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) return null;

  const task = { id: randomUUID(), projectId, title, status: 'todo' };
  tasks.push(task);
  return task;
}

function updateTask(projectId, taskId, status) {
  const taskIndex = tasks.findIndex(task => task.projectId === projectId && task.id === taskId);
  if (taskIndex === -1) return null;

  tasks[taskIndex].status = status;
  return tasks[taskIndex];
}

module.exports = {
  getAllTasks,
  createTask,
  updateTask,
};

const express = require('express');
const { sendError } = require('../../lib/errors');
const commentService = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const { message } = req.body;
  if (!message) return sendError(res, 400, 'INVALID_MESSAGE', 'Message is required');

  const comment = commentService.addComment(req.params.projectId, req.params.taskId, message);
  res.status(201).json({ comment });
});

router.get('/', (req, res) => {
  const comments = commentService.getAllComments(req.params.projectId, req.params.taskId);
  res.json({ comments });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const taskService = require('../tasks/service');

let comments = [];

function getAllComments(projectId, taskId) {
  return comments.filter(comment => comment.projectId === projectId && comment.taskId === taskId);
}

function addComment(projectId, taskId, message) {
  const task = taskService.getAllTasks(projectId).find(t => t.id === taskId);
  if (!task) return null;

  const comment = { id: randomUUID(), projectId, taskId, message };
  comments.push(comment);
  return comment;
}

module.exports = {
  getAllComments,
  addComment,
};

function sendError(res, status, code, message) {
  res.status(status).json({ error: { code, message } });
}

module.exports = {
  sendError,
};
